mapper.select:
select r.id, stu.name as user_name, r.semester, r.total_borrow, r.fav_category, r.create_time
from reading_report r
left join student stu on r.user_id = stu.id

    r.user_id = #{userId}
    and r.semester = #{semester}

order by r.create_time desc

mapper.update:
update reading_report
set total_borrow = #{totalBorrow},
    fav_category = #{favCategory},
    analysis_text = #{analysisText}
where id = #{id}
